UPDATE spells SET summary = 'Summon familiar spirit in animal form (bat, cat, crab, frog, hawk, lizard, octopus, owl, snake, fish, rat, raven, seahorse, spider, weasel). Follows your commands, can''t attack. Telepathy within 100 feet. Use action to see/hear through it. Dismissible. You can''t have multiple familiars.''' WHERE slug = 'find-familiar';
UPDATE spells SET summary = 'Curse: {@damage 1d6} necrotic on hits, disadvantage on chosen ability.''' WHERE slug = 'hex';
UPDATE spells SET summary = 'Touch object to identify magic properties, attunement, charges, or affecting spells. Or touch creature to learn affecting spells.''' WHERE slug = 'identify';
UPDATE spells SET summary = 'Write on parchment with illusion. You and designated creatures see normal writing; others see incomprehensible script or different message. {@sense truesight} reads hidden.''' WHERE slug = 'illusory-script';
UPDATE spells SET summary = 'Touch willing creature. Protected from aberrations, celestials, elementals, fey, fiends, undead. Those types disadvantage on attacks. Can''t be {@condition charmed}, {@condition frightened}, possessed.''' WHERE slug = 'protection-from-evil-and-good';
UPDATE spells SET summary = 'Ward creature within range. Attackers must save Wisdom or choose new target. Ends if warded creature attacks, casts offensive spell, or damages another.''' WHERE slug = 'sanctuary';
UPDATE spells SET summary = 'Next melee hit: {@damage 1d6} fire, target ignites. Makes CON save at turn start: fail = {@damage 1d6} fire, success = ends. Extinguishing ends spell.''' WHERE slug = 'searing-smite';
UPDATE spells SET summary = 'Create visual illusion (≤15-foot cube). Move as action. Purely visual. Creatures can check Intelligence ({@skill Investigation}) to see through. Physical interaction reveals it.''' WHERE slug = 'silent-image';
UPDATE spells SET summary = 'Roll {@dice 5d8} to determine affected HP. Creatures within 20 feet fall {@condition unconscious} in ascending HP order until damaged or shaken. Undead unaffected.''' WHERE slug = 'sleep';
UPDATE spells SET summary = '5-foot radius trap. Triggers on creature: Dexterity save or hoisted 3 feet, {@condition restrained}. Can retry at turn end. Ends when no creatures restrained.''' WHERE slug = 'snare';
UPDATE spells SET summary = 'Creature saves Wisdom or falls {@condition prone}, {@condition incapacitated}. Can''t stand. INT ≤ 4 unaffected. Retry at turn end and when damaged (advantage if damaged).''' WHERE slug = 'tasha''s-hideous-laughter';
UPDATE spells SET summary = '3-foot disk floats 3 feet up, holds 500 lbs. Immobile within 20 feet of you, follows if farther. Can''t cross 10+ foot elevation. Ends if 100+ feet away.''' WHERE slug = 'tenser''s-floating-disk';
UPDATE spells SET summary = '15-foot cube from you: Constitution save or {@damage 2d8} thunder, pushed 10 feet. Success = half, not pushed. Unsecured objects pushed 10 feet.''' WHERE slug = 'thunderwave';
UPDATE spells SET summary = 'Invisible, mindless force (AC 10, 1 HP, Strength 2). Bonus action to move 15 feet and interact with object. Can''t attack. Ends if 60+ feet away.''' WHERE slug = 'unseen-servant';
UPDATE spells SET summary = 'Ranged spell attack: {@damage 1d12} lightning. Each turn action for {@damage 1d12} automatic. Ends if use action otherwise, out of range, or has cover.''' WHERE slug = 'witch-bolt';
UPDATE spells SET summary = 'Choose aquatic adaptation (breathe water, swim speed), change appearance (height, weight, features, voice, hair), or natural weapons ({@damage 1d6} unarmed, proficiency, magic, +1).''' WHERE slug = 'alter-self';
UPDATE spells SET summary = 'Tiny beast delivers 25-word message to recipient matching description. Covers ~50 miles/day flying or ~25 miles other. Returns if unreached before spell ends.''' WHERE slug = 'animal-messenger';
UPDATE spells SET summary = 'Lock object. Only you and designated creatures open. Optionally set password. DC to break/pick increases by 10. {@spell knock} suppresses for 10 minutes.''' WHERE slug = 'arcane-lock';
UPDATE spells SET summary = 'Receive omen about action within 30 minutes: Weal (good), Woe (bad), Weal and Woe, or Nothing. Casting 2+ before long rest adds 25% cumulative chance for random reading.''' WHERE slug = 'augury';
UPDATE spells SET summary = '20-foot radius: humanoids save Charisma (can choose to fail). Suppress {@condition charmed}}/{@condition frightened} effects or make target indifferent to hostiles.''' WHERE slug = 'calm-emotions';
UPDATE spells SET summary = 'Plant four arrows/bolts. When creature enters 30 feet, arrow strikes: Dexterity save or {@damage 1d6} piercing, arrow destroyed. Designate creatures to ignore.''' WHERE slug = 'cordon-of-arrows';
UPDATE spells SET summary = 'Humanoid saves Wisdom or becomes {@condition charmed}. Must action each turn to melee attack non-self target you choose. Maintain action each turn or ends. Retry at turn end.''' WHERE slug = 'crown-of-madness';
UPDATE spells SET summary = '15-foot radius magical darkness. {@sense darkvision} and nonmagical light blocked. Moves with held object. Overlaps 2nd level or lower spell light dispels it.''' WHERE slug = 'darkness';
UPDATE spells SET summary = 'Read surface thoughts (30 feet) each turn. Probe deeper (target saves or learn reasoning/emotions). Search for thinking creatures. Penetrates 2 feet rock, 2 inches metal except lead.''' WHERE slug = 'detect-thoughts';
UPDATE spells SET summary = '5-foot cube: elemental force. Creatures within 5 feet save Strength or take {@damage 1d8} bludgeoning, pushed 10 feet. Move bonus 30 feet. Forms obscuring cloud over loose materials.''' WHERE slug = 'dust-devil';
UPDATE spells SET summary = 'Touch: Bear (CON checks, {@dice 2d6} temp HP), Bull (STR checks, double carry), Cat (DEX, no fall damage ≤20 feet), Eagle (CHA), Fox (INT), Owl (WIS).''' WHERE slug = 'enhance-ability';
UPDATE spells SET summary = 'Unwilling creature saves Constitution. Enlarge: 2× size, {@damage 1d4} extra on attacks, STR advantage. Reduce: 1/2 size, {@damage 1d4} less (min 1), STR disadvantage.''' WHERE slug = 'enlarge/reduce';
UPDATE spells SET summary = 'Creatures within range hearing you save Wisdom. Fail = disadvantage Perception except perceiving you. {@condition charmed}-immune auto-succeed. Advantage if fighting you.''' WHERE slug = 'enthrall';
UPDATE spells SET summary = 'Summon celestial/fey/fiend steed (warhorse, pony, camel, elk, mastiff). Telepathy within 1 mile. Spells targeting you target it too while mounted. Ends at 0 HP or dismiss.''' WHERE slug = 'find-steed';
UPDATE spells SET summary = 'Sense magical/mechanical traps within range: alarms, glyphs of warding, pit traps. Reveals presence and general nature but not location.''' WHERE slug = 'find-traps';
UPDATE spells SET summary = 'Evoke fiery scimitar. Action for melee spell attack: {@damage 3d6} fire. Sheds bright light 10 feet, dim 10 additional.''' WHERE slug = 'flame-blade';
